/* 3D tower loader made by: csozi | Website: www.darma-loader-darma-custom-647__csozi.darma-loader-darma-custom-647__hu*/

.darma-loader-darma-custom-647 {color: var(--loader-color, #2563eb);
  --loader-secondary-color: var(--loader-secondary-color, #60a5fa);
  --loader-bg: var(--loader-bg, #0f172a);

  scale: 3;
  height: 50px;
  width: 40px;
}

.darma-loader-darma-custom-647__box {
  position: relative;
  opacity: 0;
  left: 10px;
}

.darma-loader-darma-custom-647__side-left {
  position: absolute;
  background-color: #286cb5;
  width: 19px;
  height: 5px;
  transform: skew(0deg, -25deg);
  top: 14px;
  left: 10px;
}

.darma-loader-darma-custom-647__side-right {
  position: absolute;
  background-color: #2f85e0;
  width: 19px;
  height: 5px;
  transform: skew(0deg, 25deg);
  top: 14px;
  left: -9px;
}

.darma-loader-darma-custom-647__side-top {
  position: absolute;
  background-color: #5fa8f5;
  width: 20px;
  height: 20px;
  rotate: 45deg;
  transform: skew(-20deg, -20deg);
}

.darma-loader-darma-custom-647__box-1 {
  animation: darma-loader-darma-custom-647-from-left 4s infinite;
}

.darma-loader-darma-custom-647__box-2 {
  animation: darma-loader-darma-custom-647-from-right 4s infinite;
  animation-delay: 1s;
}

.darma-loader-darma-custom-647__box-3 {
  animation: darma-loader-darma-custom-647-from-left 4s infinite;
  animation-delay: 2s;
}

.darma-loader-darma-custom-647__box-4 {
  animation: darma-loader-darma-custom-647-from-right 4s infinite;
  animation-delay: 3s;
}

@keyframes darma-loader-darma-custom-647-from-left {
  0% {
    z-index: 20;
    opacity: 0;
    translate: -20px -6px;
  }

  20% {
    z-index: 10;
    opacity: 1;
    translate: 0px 0px;
  }

  40% {
    z-index: 9;
    translate: 0px 4px;
  }

  60% {
    z-index: 8;
    translate: 0px 8px;
  }

  80% {
    z-index: 7;
    opacity: 1;
    translate: 0px 12px;
  }

  100% {
    z-index: 5;
    translate: 0px 30px;
    opacity: 0;
  }
}

@keyframes darma-loader-darma-custom-647-from-right {
  0% {
    z-index: 20;
    opacity: 0;
    translate: 20px -6px;
  }

  20% {
    z-index: 10;
    opacity: 1;
    translate: 0px 0px;
  }

